import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Container, Row, Col, Button, Spinner, Card } from 'react-bootstrap';
import api from '../services/api';
import '../styles/card.css';

function EventDetailPage() {
  const { id } = useParams();
  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchEventDetail = async () => {
      try {
        const response = await api.get(`/events/${id}`);
        setEvent(response.data);
      } catch (err) {
        console.error('Lỗi:', err);
      } finally {
        setLoading(false);
      }
    };
    fetchEventDetail();
  }, [id]);

  if (loading) return <div className="text-center mt-5"><Spinner animation="border" /></div>;
  if (!event) return <Container className="mt-5"><h3>Không tìm thấy sự kiện</h3></Container>;

  const eventDate = new Date(event.event_date);

  return (
    <Container fluid className="py-5 px-lg-5" style={{ backgroundColor: '#f8f9fa', minHeight: '100vh' }}>
      <Row className="justify-content-center">
        <Col xs={12}>
          <Card className="ticket-detail-card shadow-lg">
            
            {/* HIỆU ỨNG ĐỤC LỖ VÀ NÉT ĐỨT */}
            <div id="circle1" className="circle"></div>
            <div id="circle2" className="circle"></div>
            <svg width="4" height="415" viewBox="0 0 4 415" fill="none" xmlns="http://www.w3.org/2000/svg" id="vertical-dashed">
              <path stroke="#27272A" strokeWidth="4" strokeLinecap="round" strokeDasharray="4 10" d="M2 2v411"></path>
            </svg>

            <Row className="g-0 align-items-stretch">
              {/* CỘT THÔNG TIN (40%) */}
              <Col md={5}>
                <div className="ticket-body">
                  <h1 className="ticket-event-title">{event.title}</h1>
                  <p className="text-muted mb-4">by {event.artist_name || 'Organizer'}</p>

                  <div className="ticket-info-list">
                    <div className="info-item">
                      <div className="ticket-label">Thời gian</div>
                      <div className="ticket-value">
                        <i className="fa-regular fa-calendar me-2"></i>
                        {eventDate.toLocaleDateString('vi-VN')} - {eventDate.toLocaleTimeString('vi-VN', {hour:'2-digit', minute:'2-digit'})}
                      </div>
                    </div>

                    <div className="info-item">
                      <div className="ticket-label">Địa điểm</div>
                      <div className="ticket-value">
                        <i className="fa-solid fa-location-dot me-2 text-danger"></i>
                        {event.location}
                      </div>
                    </div>

                    <div className="info-item">
                      <div className="ticket-label">Giá vé từ</div>
                      <div className="ticket-value price-text">
                        {event.price ? `${event.price.toLocaleString('vi-VN')} VND` : 'Liên hệ'}
                      </div>
                    </div>
                  </div>

                  <Button variant="dark" className="btn-buy-ticket-large w-100 mt-4">
                    MUA VÉ NGAY
                  </Button>
                </div>
              </Col>

              {/* CỘT HÌNH ẢNH (60%) */}
              <Col md={7}>
                <div className="ticket-image-wrapper h-100">
                  <img 
                    src={event.banner_image ? require(`../assets/images/${event.banner_image}`) : 'https://via.placeholder.com/800x600'} 
                    alt={event.title} 
                    className="img-main-ticket"
                  />
                </div>
              </Col>
            </Row>
          </Card>

          {/* MÔ TẢ CHI TIẾT */}
          <div className="mt-5 px-4">
            <h4 className="fw-bold mb-3">Mô tả sự kiện</h4>
            <div className="event-desc-content p-4 bg-white rounded-4 shadow-sm">
              {event.description}
            </div>
          </div>
        </Col>
      </Row>
    </Container>
  );
}

export default EventDetailPage;
